     1→"use client";
     2→
     3→import { useChat } from "@ai-sdk/react";
     4→import {
     5→  skipToken,
     6→  useMutation,
     7→  useQuery,
     8→  useQueryClient,
     9→} from "@tanstack/react-query";
    10→import {
    11→  DefaultChatTransport,
    12→  lastAssistantMessageIsCompleteWithToolCalls,
    13→} from "ai";
    14→import Image from "next/image";
    15→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
    16→import {
    17→  Conversation,
    18→  ConversationContent,
    19→  ConversationScrollButton,
    20→} from "@/components/ai-elements/conversation";
    21→import { Message, MessageContent } from "@/components/ai-elements/message";
    22→import type {
    23→  ImageModelId,
    24→  VideoModelId,
    25→} from "@/components/product/editor/agent/AgentModelSelector";
    26→import { AssetsSidebar } from "@/components/product/editor/agent/AssetsSidebar";
    27→import ChatActionsMenu from "@/components/product/editor/agent/ChatActionsMenu";
    28→import { ChatHistorySidebar } from "@/components/product/editor/agent/ChatHistorySidebar";
    29→import {
    30→  extractImagePollingData,
    31→  extractMediaUrls,
    32→  extractVideoPollingData,
    33→} from "@/components/product/editor/agent/components/utils";
    34→import InputBar from "@/components/product/editor/agent/InputBar";
    35→import MessagePartRenderer from "@/components/product/editor/agent/MessagePartRenderer";
    36→import SystemInstructionsDialog from "@/components/product/editor/agent/SystemInstructionsDialog";
    37→import {
    38→  getGlobalSystemInstructions,
    39→  saveGlobalSystemInstructions,
    40→} from "@/components/product/editor/agent/utils";
    41→import ProfileDialog from "@/components/shared/dialogs/ProfileDialog";
    42→import ProfileDropdown from "@/components/shared/dropdown/ProfileDropdown";
    43→import { Icons } from "@/components/shared/helper/Icons";
    44→import { ToolTipWrapper } from "@/components/shared/uiWrappers/ToolTipWrapper";
    45→import { Button } from "@/components/ui/button";
    46→import { Dialog, DialogContent, DialogTrigger } from "@/components/ui/dialog";
    47→import { Spinner } from "@/components/ui/spinner";
    48→import { useCredits } from "@/context/CreditProvider";
    49→import { useSidebar } from "@/context/SidebarContext";
    50→import { authClient } from "@/lib/auth-client";
    51→import {
    52→  generateCloudFrontUrl,
    53→  generateS3KeyFromPredictionId,
    54→} from "@/lib/utils/s3-common";
    55→import { useAgentChatStore } from "@/state/stores/agentChatStore";
    56→import { useCanvasAgentBridge } from "@/state/stores/canvasAgentBridge";
    57→import { useTRPC } from "@/trpc/client";
    58→
    59→// Type for locally-created chats (not yet on server)
    60→type LocalChat = {
    61→  id: string;
    62→  title: string;
    63→  createdAt: Date;
    64→  lastUsedAt: Date;
    65→};
    66→
    67→export const ChatClient = ({
    68→  projectId,
    69→  isOpen,
    70→  setIsOpen,
    71→}: {
    72→  projectId: string;
    73→  isOpen: boolean;
    74→  setIsOpen: (isOpen: boolean) => void;
    75→}) => {
    76→  const { refreshCredits } = useCredits();
    77→  const { userDetails, loading } = useCredits();
    78→  const { data: session } = authClient.useSession();
    79→  const user = session?.user;
    80→  const { toggleSidebar } = useSidebar();
    81→  const userId = user?.id;
    82→  const executeCommand = useCanvasAgentBridge((store) => store.executeCommand);
    83→  const clearCanvasSelection = useCanvasAgentBridge(
    84→    (store) => store.clearSelection,
    85→  );
    86→  const registerSendMessage = useAgentChatStore(
    87→    (store) => store.registerSendMessage,
    88→  );
    89→  const [activeChatId, setActiveChatId] = useState<string | null>(() => {
    90→    if (typeof window === "undefined") return null;
    91→    return localStorage.getItem(`active-chat-${projectId}`);
    92→  });
    93→
    94→  // Local new chats (created with UUID, not yet on server)
    95→  // These get merged with server chats for display
    96→  const [localNewChats, setLocalNewChats] = useState<LocalChat[]>([]);
    97→
    98→  // Ref to hold the current chatId - prevents stale closures in useChat transport
    99→  const activeChatIdRef = useRef<string | null>(null);
   100→  activeChatIdRef.current = activeChatId;
   101→
   102→  const [currenttab, setCurrenttab] = useState<"chat" | "assets" | "history">(
   103→    "chat",
   104→  );
   105→
   106→  const [isSystemDialogOpen, setIsSystemDialogOpen] = useState(false);
   107→  const [globalSystemInstructions, setGlobalSystemInstructions] = useState("");
   108→
   109→  // Model selection state for Auto/Manual mode
   110→  const [isAutoMode, setIsAutoMode] = useState(true);
   111→  const [selectedImageModel, setSelectedImageModel] =
   112→    useState<ImageModelId>("seedream-4.5");
   113→  const [selectedVideoModel, setSelectedVideoModel] =
   114→    useState<VideoModelId>("veo3.1");
   115→
   116→  // Refs to hold model selection - prevents stale closures in useChat transport
   117→  const modelSelectionRef = useRef({
   118→    isAutoMode: true,
   119→    imageModel: "seedream-4.5" as ImageModelId,
   120→    videoModel: "veo3.1" as VideoModelId,
   121→  });
   122→  // Keep refs in sync with state
   123→  modelSelectionRef.current = {
   124→    isAutoMode,
   125→    imageModel: selectedImageModel,
   126→    videoModel: selectedVideoModel,
   127→  };
   128→
   129→  // tRPC for loading chats and messages
   130→  const trpc = useTRPC();
   131→  const queryClient = useQueryClient();
   132→
   133→  // Fetch all chats for the project (sorted by lastUsedAt desc from backend)
   134→  const { data: chatsData, isPending: isLoadingChats } = useQuery({
   135→    ...trpc.chat.getChats.queryOptions({ projectId }),
   136→    enabled: Boolean(projectId),
   137→  });
   138→
   139→  // Merge server chats with local new chats (local chats appear first as they're newest)
   140→  const allChats = useMemo(() => {
   141→    const serverChats = chatsData?.chats ?? [];
   142→    const serverChatIds = new Set(serverChats.map((c) => c.id));
   143→
   144→    // Filter out local chats that now exist on server (they've been created)
   145→    const pendingLocalChats = localNewChats.filter(
   146→      (c) => !serverChatIds.has(c.id),
   147→    );
   148→
   149→    // Local new chats first (newest), then server chats
   150→    return [...pendingLocalChats, ...serverChats];
   151→  }, [chatsData?.chats, localNewChats]);
   152→
   153→  // Show empty state when no chats exist after loading completes
   154→  const showEmptyState = !isLoadingChats && allChats.length === 0;
   155→
   156→  // Clean up local chats that now exist on server
   157→  useEffect(() => {
   158→    if (!chatsData?.chats) return;
   159→    const serverChatIds = new Set(chatsData.chats.map((c) => c.id));
   160→    setLocalNewChats((prev) => prev.filter((c) => !serverChatIds.has(c.id)));
   161→  }, [chatsData?.chats]);
   162→
   163→  // Auto-select first chat when data loads and no chat is selected (and none in storage)
   164→  useEffect(() => {
   165→    if (!activeChatId && allChats[0]) {
   166→      const firstChatId = allChats[0].id;
   167→      setActiveChatId(firstChatId);
   168→      localStorage.setItem(`active-chat-${projectId}`, firstChatId);
   169→    }
   170→  }, [activeChatId, allChats, projectId]);
   171→
   172→  // If active chat was deleted, fall back to first available
   173→  useEffect(() => {
   174→    if (!activeChatId || allChats.length === 0) return;
   175→    const stillExists = allChats.some((c) => c.id === activeChatId);
   176→    if (!stillExists) {
   177→      setActiveChatId(allChats[0]?.id ?? null);
   178→    }
   179→  }, [activeChatId, allChats]);
   180→
   181→  // Check if this is an optimistically added chat (not yet on server)
   182→  const isOptimisticChat = useMemo(() => {
   183→    if (!activeChatId) return true;
   184→    const serverChats = chatsData?.chats ?? [];
   185→    return !serverChats.some((c) => c.id === activeChatId);
   186→  }, [activeChatId, chatsData?.chats]);
   187→
   188→  // Fetch messages for the selected chat (skip for optimistic chats)
   189→  const {
   190→    data: chatData,
   191→    isPending: isLoadingMessages,
   192→    isSuccess: hasLoadedMessages,
   193→  } = useQuery({
   194→    ...trpc.chat.getMessages.queryOptions(
   195→      activeChatId && !isOptimisticChat ? { chatId: activeChatId } : skipToken,
   196→    ),
   197→    enabled: Boolean(activeChatId) && !isOptimisticChat,
   198→  });
   199→
   200→  // Track processed tool calls to avoid duplicate canvas additions
   201→  const processedToolCallsRef = useRef<Set<string>>(new Set());
   202→
   203→  // Track which chats have been synced to server (to avoid redundant invalidations)
   204→  const syncedChatsRef = useRef<Set<string>>(new Set());
   205→
   206→  // Get current selection from bridge
   207→  // Note: We use a selector to avoid re-rendering ChatClient on every selection change
   208→  // The ref will hold the latest value for the transport callback
   209→  const selectionRef = useRef<any[]>([]);
   210→  useCanvasAgentBridge(
   211→    useCallback((state) => {
   212→      selectionRef.current = state.selection;
   213→      return state.selection;
   214→    }, []),
   215→  );
   216→
   217→  const { messages, sendMessage, status, setMessages, stop } = useChat({
   218→    id: projectId, // Use chatId for requests (existing or pre-generated)
   219→    transport: useMemo(
   220→      () =>
   221→        new DefaultChatTransport({
   222→          api: "/api/agents/v1",
   223→          body: () => {
   224→            const sel = modelSelectionRef.current;
   225→            const modelSelection = {
   226→              isAutoMode: sel.isAutoMode,
   227→              imageModel: sel.isAutoMode ? null : sel.imageModel,
   228→              videoModel: sel.isAutoMode ? null : sel.videoModel,
   229→            };
   230→
   231→            return {
   232→              globalSystemInstructions,
   233→              chatId: activeChatIdRef.current,
   234→              modelSelection,
   235→              selection: selectionRef.current, // Inject selection context
   236→            };
   237→          },
   238→          prepareSendMessagesRequest({
   239→            messages: requestMessages,
   240→            id: requestId,
   241→          }) {
   242→            const sel = modelSelectionRef.current;
   243→            const modelSelection = {
   244→              isAutoMode: sel.isAutoMode,
   245→              imageModel: sel.isAutoMode ? null : sel.imageModel,
   246→              videoModel: sel.isAutoMode ? null : sel.videoModel,
   247→            };
   248→
   249→            return {
   250→              body: {
   251→                message: requestMessages.at(-1),
   252→                id: requestId, // projectId
   253→                chatId: activeChatIdRef.current,
   254→                globalSystemInstructions,
   255→                modelSelection,
   256→                selection: selectionRef.current, // Inject selection context
   257→              },
   258→            };
   259→          },
   260→          // eslint-disable-next-line react-hooks/exhaustive-deps
   261→        }),
   262→      [],
   263→    ), // Stable transport, refs provide fresh values
   264→    sendAutomaticallyWhen: lastAssistantMessageIsCompleteWithToolCalls,
   265→    onToolCall({ toolCall }) {
   266→      if (toolCall.dynamic) {
   267→        return;
   268→      }
   269→    },
   270→    onFinish({ message }) {
   271→      refreshCredits();
   272→
   273→      // Invalidate chat list if this chat hasn't been synced yet
   274→      // This ensures isOptimisticChat becomes false after first message
   275→      const currentChatId = activeChatIdRef.current;
   276→      if (currentChatId && !syncedChatsRef.current.has(currentChatId)) {
   277→        syncedChatsRef.current.add(currentChatId);
   278→        queryClient.invalidateQueries({
   279→          queryKey: trpc.chat.getChats.queryKey({ projectId }),
   280→        });
   281→      }
   282→
   283→      // Add media from completed tool calls to canvas
   284→      if (message.role === "assistant" && message.parts) {
   285→        for (const part of message.parts) {
   286→          // Type guard: check if part is a tool part with output
   287→          const isToolPart =
   288→            typeof part === "object" &&
   289→            part !== null &&
   290→            "type" in part &&
   291→            typeof part.type === "string" &&
   292→            part.type.startsWith("tool-") &&
   293→            "state" in part &&
   294→            part.state === "output-available" &&
   295→            "output" in part &&
   296→            part.output !== undefined &&
   297→            "toolCallId" in part &&
   298→            typeof part.toolCallId === "string";
   299→
   300→          if (!isToolPart) continue;
   301→
   302→          const toolCallId = part.toolCallId;
   303→          const output = part.output;
   304→
   305→          // Skip if we've already processed this tool call
   306→          if (processedToolCallsRef.current.has(toolCallId)) {
   307→            continue;
   308→          }
   309→
   310→          // Mark as processed before attempting to add (prevents duplicates on retry)
   311→          processedToolCallsRef.current.add(toolCallId);
   312→
   313→          // Extract video polling data (videos that need polling)
   314→          const videoPollingData = extractVideoPollingData(output);
   315→          if (videoPollingData) {
   316→            // Generate S3 key/URL upfront using predictionId
   317→            const s3Key = generateS3KeyFromPredictionId(
   318→              videoPollingData.predictionId,
   319→              "video-generation",
   320→              0, // index for single video
   321→              ".mp4", // Video extension
   322→            );
   323→            const s3Url = generateCloudFrontUrl(s3Key);
   324→
   325→            // Extend polling data with S3 URL
   326→            const extendedVideoPollingData = {
   327→              ...videoPollingData,
   328→              s3Url,
   329→            };
   330→
   331→            const baseMetadata: Record<string, unknown> = {
   332→              source: "agent-chat",
   333→              mediaType: "video",
   334→              toolCallId,
   335→              chatId: activeChatIdRef.current,
   336→              projectId,
   337→              createdAt: new Date().toISOString(),
   338→              model: modelSelectionRef.current.isAutoMode
   339→                ? "auto"
   340→                : modelSelectionRef.current.videoModel,
   341→            };
   342→
   343→            executeCommand({
   344→              type: "add",
   345→              mediaType: "video",
   346→              objectId: `${toolCallId}-0`, // Generate stable ID (videos with polling are typically single)
   347→              pollingData: extendedVideoPollingData,
   348→              metadata: baseMetadata,
   349→            }).catch((error: unknown) => {
   350→              console.error("Failed to add video with polling:", error);
   351→              // Remove from processed set on error so it can be retried
   352→              processedToolCallsRef.current.delete(toolCallId);
   353→            });
   354→            continue;
   355→          }
   356→
   357→          // Extract image polling data (images that need polling)
   358→          const imagePollingData = extractImagePollingData(output);
   359→          if (imagePollingData) {
   360→            // Generate S3 key/URL upfront using predictionId
   361→            const s3Key = generateS3KeyFromPredictionId(
   362→              imagePollingData.predictionId,
   363→              "image-generation", // Default toolName, can be enhanced later
   364→              0, // index for single image
   365→              ".webp", // Default extension
   366→            );
   367→            const s3Url = generateCloudFrontUrl(s3Key);
   368→
   369→            // Extend polling data with S3 URL (s3Key not needed for persistence)
   370→            const extendedPollingData = {
   371→              ...imagePollingData,
   372→              s3Url,
   373→            };
   374→
   375→            const baseMetadata: Record<string, unknown> = {
   376→              source: "agent-chat",
   377→              mediaType: "image",
   378→              toolCallId,
   379→              chatId: activeChatIdRef.current,
   380→              projectId,
   381→              createdAt: new Date().toISOString(),
   382→              model: modelSelectionRef.current.isAutoMode
   383→                ? "auto"
   384→                : modelSelectionRef.current.imageModel,
   385→            };
   386→
   387→            executeCommand({
   388→              type: "add",
   389→              mediaType: "image",
   390→              objectId: `${toolCallId}-0`, // Generate stable ID (images with polling are typically single)
   391→              pollingData: extendedPollingData,
   392→              metadata: baseMetadata,
   393→            }).catch((error: unknown) => {
   394→              console.error("Failed to add image with polling:", error);
   395→              // Remove from processed set on error so it can be retried
   396→              processedToolCallsRef.current.delete(toolCallId);
   397→            });
   398→            continue;
   399→          }
   400→
   401→          // Extract regular media URLs (images and direct video URLs)
   402→          const media = extractMediaUrls(output);
   403→          if (media && media.type !== "audio") {
   404→            // Audio doesn't go to canvas, skip it
   405→            const mediaType = media.type as "image" | "video";
   406→
   407→            // Generate stable IDs: toolCallId + index (simple and reliable)
   408→            // CustomToolOutput generates the same IDs deterministically, no store needed
   409→            const stableIds = media.urls.map(
   410→              (_, index) => `${toolCallId}-${index}`,
   411→            );
   412→
   413→            // Add to canvas with stable IDs
   414→            const addPromises = media.urls.map((url: string, index: number) =>
   415→              executeCommand({
   416→                type: "add",
   417→                url,
   418→                mediaType,
   419→                objectId: stableIds[index], // Pass stable ID to canvas
   420→                metadata: {
   421→                  source: "agent-chat",
   422→                  mediaType,
   423→                  toolCallId,
   424→                  mediaIndex: index,
   425→                  chatId: activeChatIdRef.current,
   426→                  projectId,
   427→                  createdAt: new Date().toISOString(),
   428→                },
   429→              }),
   430→            );
   431→
   432→            Promise.all(addPromises).catch((error: unknown) => {
   433→              console.error("Failed to add media to canvas:", error);
   434→              // Remove from processed set on error so it can be retried
   435→              processedToolCallsRef.current.delete(toolCallId);
   436→            });
   437→          }
   438→        }
   439→      }
   440→    },
   441→    onError(error) {
   442→      console.error("Chat error:", error);
   443→      // Error will be displayed in the messages stream from server
   444→    },
   445→  });
   446→
   447→  // Register sendMessage for external components (e.g., MediaNodeToolbar)
   448→  useEffect(() => {
   449→    type MessagePart =
   450→      | { type: "text"; text: string }
   451→      | { type: "file"; url: string; mediaType: string; filename?: string };
   452→
   453→    const wrappedSendMessage = async (parts: MessagePart[]) => {
   454→      await sendMessage({ role: "user", parts });
   455→    };
   456→    registerSendMessage(wrappedSendMessage);
   457→    return () => registerSendMessage(null);
   458→  }, [sendMessage, registerSendMessage]);
   459→
   460→  // Load from localStorage when user changes
   461→  useEffect(() => {
   462→    setGlobalSystemInstructions(getGlobalSystemInstructions(userId));
   463→  }, [userId]);
   464→
   465→  // Track if we've already set messages to avoid duplicate initialization
   466→  const hasSetMessagesRef = useRef(false);
   467→  const lastChatIdRef = useRef<string | null>(null);
   468→
   469→  // Track if chat was optimistic to detect transition to server chat
   470→  const wasOptimisticRef = useRef(isOptimisticChat);
   471→
   472→  // Set messages when tRPC query completes (or reset when chat changes)
   473→  useEffect(() => {
   474→    // Reset if chat changed
   475→    if (activeChatId !== lastChatIdRef.current) {
   476→      hasSetMessagesRef.current = false;
   477→      lastChatIdRef.current = activeChatId;
   478→      // Clear canvas selection when switching chats
   479→      clearCanvasSelection();
   480→    }
   481→
   482→    // Reset if chat transitioned from optimistic to server (messages now available from DB)
   483→    if (wasOptimisticRef.current && !isOptimisticChat) {
   484→      hasSetMessagesRef.current = false;
   485→    }
   486→    wasOptimisticRef.current = isOptimisticChat;
   487→
   488→    if (hasLoadedMessages && chatData?.messages && !hasSetMessagesRef.current) {
   489→      if (chatData.messages.length > 0) {
   490→        // Pre-populate processedToolCallsRef with tool calls from loaded messages
   491→        // to prevent re-processing when onFinish fires with accumulated parts
   492→        for (const msg of chatData.messages) {
   493→          if (msg.role === "assistant" && msg.parts) {
   494→            for (const part of msg.parts) {
   495→              if (
   496→                typeof part === "object" &&
   497→                part !== null &&
   498→                "toolCallId" in part &&
   499→                typeof part.toolCallId === "string"
   500→              ) {
   501→                processedToolCallsRef.current.add(part.toolCallId);
   502→              }
   503→            }
   504→          }
   505→        }
   506→        setMessages(chatData.messages);
   507→      }
   508→      hasSetMessagesRef.current = true;
   509→    }
   510→  }, [
   511→    hasLoadedMessages,
   512→    chatData?.messages,
   513→    setMessages,
   514→    activeChatId,
   515→    isOptimisticChat,
   516→    clearCanvasSelection,
   517→  ]);
   518→
   519→  // Dedupe messages by ID - ensures latest version wins during streaming updates with tool calls
   520→  // TODO: Uncomment this if we want to deduplicate messages
   521→  // const processedMessages = useMemo(() => {
   522→  //   const messageMap = new Map<string, UIMessage>();
   523→  //   for (const msg of messages) {
   524→  //     messageMap.set(msg.id, msg);
   525→  //   }
   526→  //   return Array.from(messageMap.values());
   527→  // }, [messages]);
   528→
   529→  const handleNewChat = useCallback(() => {
   530→    // Generate a new chat ID - it will be created on server when first message is sent
   531→    const newChatId = crypto.randomUUID();
   532→    const now = new Date();
   533→
   534→    // Add to local chats array (will be synced with server after first message)
   535→    const newLocalChat: LocalChat = {
   536→      id: newChatId,
   537→      title: "New Chat",
   538→      createdAt: now,
   539→      lastUsedAt: now,
   540→    };
   541→    setLocalNewChats((prev) => [newLocalChat, ...prev]);
   542→
   543→    // Reset all refs for the new chat
   544→    hasSetMessagesRef.current = false;
   545→    lastChatIdRef.current = newChatId;
   546→    processedToolCallsRef.current.clear();
   547→    syncedChatsRef.current.delete(newChatId); // Not needed but explicit cleanup
   548→
   549→    // Clear canvas selection when creating new chat
   550→    clearCanvasSelection();
   551→
   552→    // Update state
   553→    setActiveChatId(newChatId);
   554→    setMessages([]);
   555→    setCurrenttab("chat");
   556→  }, [setMessages, clearCanvasSelection]);
   557→
   558→  const handleSelectChat = (chatId: string) => {
   559→    // Skip if re-selecting the same chat (prevents clearing messages)
   560→    if (chatId === activeChatId) {
   561→      return;
   562→    }
   563→
   564→    // Reset refs for the selected chat
   565→    hasSetMessagesRef.current = false;
   566→    lastChatIdRef.current = chatId;
   567→    processedToolCallsRef.current.clear();
   568→
   569→    // Clear canvas selection when switching chats
   570→    clearCanvasSelection();
   571→
   572→    setActiveChatId(chatId);
   573→    localStorage.setItem(`active-chat-${projectId}`, chatId);
   574→    setMessages([]);
   575→  };
   576→
   577→  // Mutation for deleting chats
   578→  const deleteChatMutation = useMutation(
   579→    trpc.chat.deleteChat.mutationOptions({
   580→      onError: (error) => {
   581→        console.error("Failed to delete chat:", error);
   582→        // Refetch to restore state on error
   583→        queryClient.invalidateQueries({
   584→          queryKey: trpc.chat.getChats.queryKey({ projectId }),
   585→        });
   586→      },
   587→      onSuccess: () => {
   588→        queryClient.invalidateQueries({
   589→          queryKey: trpc.chat.getChats.queryKey({ projectId }),
   590→        });
   591→      },
   592→    }),
   593→  );
   594→
   595→  // Mutation for renaming chats
   596→  const renameChatMutation = useMutation(
   597→    trpc.chat.updateTitle.mutationOptions({
   598→      onError: (error) => {
   599→        console.error("Failed to rename chat:", error);
   600→        // Refetch to restore state on error
   601→        queryClient.invalidateQueries({
   602→          queryKey: trpc.chat.getChats.queryKey({ projectId }),
   603→        });
   604→      },
   605→    }),
   606→  );
   607→
   608→  const handleDeleteChat = async (chatId: string) => {
   609→    // Check if this is the last chat (only 1 chat remaining and we're deleting it)
   610→    const isLastChat = allChats.length === 1 && allChats[0].id === chatId;
   611→
   612→    // Remove from local chats if it's an optimistic chat
   613→    setLocalNewChats((prev) => prev.filter((c) => c.id !== chatId));
   614→
   615→    // If deleting the active chat, clear selection
   616→    if (activeChatId === chatId) {
   617→      setActiveChatId(null);
   618→      setMessages([]);
   619→
   620→      // Reset refs
   621→      hasSetMessagesRef.current = false;
   622→      lastChatIdRef.current = null;
   623→      processedToolCallsRef.current.clear();
   624→    }
   625→
   626→    // Only call server delete if it's a server-synced chat (not a local-only optimistic chat)
   627→    const isServerChat = chatsData?.chats?.some((c) => c.id === chatId);
   628→    if (isServerChat) {
   629→      await deleteChatMutation.mutateAsync({ chatId });
   630→    }
   631→
   632→    // If this was the last chat, automatically create a new one
   633→    if (isLastChat) {
   634→      handleNewChat();
   635→    }
   636→  };
   637→
   638→  const handleRenameChat = async (chatId: string, title: string) => {
   639→    await renameChatMutation.mutateAsync({ chatId, title });
   640→    // Refetch to show updated title
   641→    queryClient.invalidateQueries({
   642→      queryKey: trpc.chat.getChats.queryKey({ projectId }),
   643→    });
   644→  };
   645→
   646→  // Seed chat with an initial prompt from the editor (if provided via localStorage).
   647→  // This is a one-time seed: the key is cleared immediately after use.
   648→  useEffect(() => {
   649→    // Don't send if messages already exist
   650→    if (messages.length > 0) return;
   651→
   652→    // Don't send if chats are still loading (wait for chat to be available)
   653→    if (isLoadingChats) return;
   654→
   655→    // Don't send if chatId is not ready yet
   656→    // If no chat exists after loading, create one first
   657→    if (!activeChatId) {
   658→      // If chats finished loading but no chat exists, create one
   659→      // The effect will run again when activeChatId is set
   660→      if (allChats.length === 0) {
   661→        handleNewChat();
   662→      }
   663→      return;
   664→    }
   665→
   666→    if (typeof window === "undefined") return;
   667→
   668→    try {
   669→      const stored = window.localStorage.getItem("image-editor-initial-prompt");
   670→      const trimmed = stored?.trim();
   671→      if (!trimmed) return;
   672→
   673→      // fire-and-forget; we don't need to await here
   674→      sendMessage({
   675→        role: "user",
   676→        parts: [
   677→          {
   678→            type: "text",
   679→            text: trimmed,
   680→          },
   681→        ],
   682→      });
   683→
   684→      window.localStorage.removeItem("image-editor-initial-prompt");
   685→    } catch {
   686→      // Ignore localStorage errors
   687→    }
   688→  }, [
   689→    messages.length,
   690→    activeChatId,
   691→    isLoadingChats,
   692→    allChats.length,
   693→    sendMessage,
   694→    handleNewChat,
   695→  ]);
   696→
   697→  return (
   698→    <div
   699→      aria-label="Chat"
   700→      className="flex min-h-0 w-full flex-1 flex-col overflow-hidden"
   701→      role="main"
   702→    >
   703→      {currenttab === "chat" && (
   704→        <>
   705→          {/* Top actions/header */}
   706→          <div className="sticky top-0 z-40 w-full flex-between border-border-500 border-b pb-3">
   707→            <div className="flex-center gap-2">
   708→              <Button
   709→                className="size-8 flex-center cursor-pointer rounded-full text-white hover:bg-background-400 disabled:cursor-not-allowed disabled:opacity-50 md:hidden md:size-7"
   710→                onClick={toggleSidebar}
   711→                size="none"
   712→                variant="none"
   713→              >
   714→                <Icons.menu className="size-4" />
   715→              </Button>
   716→              <ToolTipWrapper label="New chat">
   717→                <Button
   718→                  aria-label="New chat"
   719→                  className="size-8 flex-center cursor-pointer rounded-full text-white hover:bg-background-400 disabled:cursor-not-allowed disabled:opacity-50 md:size-7"
   720→                  disabled={messages.length === 0}
   721→                  onClick={handleNewChat}
   722→                  size="none"
   723→                  variant="none"
   724→                >
   725→                  <Icons.newChat className="size-4" />
   726→                </Button>
   727→              </ToolTipWrapper>
   728→
   729→              <ToolTipWrapper label="History">
   730→                <Button
   731→                  aria-label="Chat history"
   732→                  className="size-8 flex-center cursor-pointer rounded-full text-white hover:bg-background-400 disabled:cursor-not-allowed disabled:opacity-50 md:size-7"
   733→                  onClick={() => setCurrenttab("history")}
   734→                  size="none"
   735→                  variant="none"
   736→                >
   737→                  <Icons.dashboardHistory className="size-4" />
   738→                </Button>
   739→              </ToolTipWrapper>
   740→
   741→              <ToolTipWrapper label="Assets">
   742→                <Button
   743→                  aria-label="Assets"
   744→                  className="size-8 flex-center cursor-pointer rounded-full text-white hover:bg-background-400 disabled:cursor-not-allowed disabled:opacity-50 md:size-7"
   745→                  onClick={() => setCurrenttab("assets")}
   746→                  size="none"
   747→                  variant="none"
   748→                >
   749→                  <Icons.assetsHistory className="size-4" />
   750→                </Button>
   751→              </ToolTipWrapper>
   752→              <ChatActionsMenu
   753→                onEditSystemInstructions={() => setIsSystemDialogOpen(true)}
   754→              />
   755→              <div className="max-md:hidden">
   756→                {isOpen && (
   757→                  <ToolTipWrapper label="Close chat">
   758→                    <Button
   759→                      className="size-8 flex-center cursor-pointer rounded-full text-white hover:bg-background-400 disabled:cursor-not-allowed disabled:opacity-50 md:size-7"
   760→                      onClick={() => setIsOpen(false)}
   761→                      size="none"
   762→                      variant="none"
   763→                    >
   764→                      <Icons.collapse className="size-4" />
   765→                    </Button>
   766→                  </ToolTipWrapper>
   767→                )}
   768→              </div>
   769→            </div>
   770→            <div className="flex-center gap-2 md:gap-2.5">
   771→              <Dialog>
   772→                <DialogTrigger className="w-full">
   773→                  <div className="flex-center gap-0.5">
   774→                    <Icons.credits className="size-4 text-white" />
   775→                    {!userDetails || loading ? (
   776→                      <div className="flex-center text-[#808080]">
   777→                        <div className="h-[21px] w-10 animate-shimmer rounded bg-linear-to-r from-[#292929] via-[#363636] to-[#292929]" />
   778→                      </div>
   779→                    ) : (
   780→                      <div className="text-sm text-white">
   781→                        {userDetails?.creditBalance.toFixed(0)}
   782→                      </div>
   783→                    )}{" "}
   784→                  </div>
   785→                </DialogTrigger>
   786→                <DialogContent className="custom-scrollbar max-h-[80vh] w-full max-w-[80vw] overflow-y-scroll rounded-xl border-none bg-neutral-800 p-0 px-0 font-inter focus:outline-none">
   787→                  <ProfileDialog />
   788→                </DialogContent>
   789→              </Dialog>
   790→
   791→              <ProfileDropdown>
   792→                {user?.image ? (
   793→                  <Image
   794→                    alt="Profile"
   795→                    className="size-9 rounded-full bg-white/10 object-cover md:size-7"
   796→                    height={40}
   797→                    loading="eager"
   798→                    src={user?.image}
   799→                    width={40}
   800→                  />
   801→                ) : (
   802→                  <Image
   803→                    alt="Profile"
   804→                    className="size-9 rounded-full bg-white/10 object-cover md:size-7"
   805→                    height={40}
   806→                    loading="eager"
   807→                    src="https://d2weamipq0hk4d.cloudfront.net/assets/asset_1753857552700.webp"
   808→                    unoptimized={true}
   809→                    width={40}
   810→                  />
   811→                )}
   812→              </ProfileDropdown>
   813→            </div>
   814→          </div>
   815→
   816→          {/* Empty state when no chats exist */}
   817→          {showEmptyState ? (
   818→            <div className="flex min-h-0 flex-1 flex-col items-center justify-center gap-4 text-center">
   819→              <div className="flex flex-col items-center gap-3">
   820→                <div className="flex size-16 items-center justify-center rounded-full bg-background-400">
   821→                  <Icons.newChat className="size-8 text-gray-400" />
   822→                </div>
   823→                <h2 className="font-medium text-lg text-white">
   824→                  No conversations yet
   825→                </h2>
   826→                <p className="max-w-sm text-gray-400 text-sm">
   827→                  Start a new chat to begin creating images, videos, and more
   828→                  with AI
   829→                </p>
   830→              </div>
   831→              <Button
   832→                className="mt-2 gap-2"
   833→                onClick={handleNewChat}
   834→                variant="default"
   835→              >
   836→                <Icons.newChat className="size-4" />
   837→                Start New Chat
   838→              </Button>
   839→            </div>
   840→          ) : (
   841→            <>
   842→              {/* Scrollable conversation area */}
   843→              <div className="flex min-h-0 flex-1 gap-3 overflow-hidden">
   844→                <Conversation className="mx-auto w-full flex-1 overflow-y-auto">
   845→                  <ConversationContent className="space-y-6 py-3">
   846→                    {isLoadingChats ||
   847→                    (activeChatId &&
   848→                      !isOptimisticChat &&
   849→                      isLoadingMessages &&
   850→                      messages.length === 0) ? (
   851→                      <div className="flex-center py-8">
   852→                        <Spinner size={24} />
   853→                        <span className="ml-3 text-gray-400 text-sm">
   854→                          Loading messages...
   855→                        </span>
   856→                      </div>
   857→                    ) : (
   858→                      messages
   859→                        ?.filter(
   860→                          (message) =>
   861→                            message.parts && message.parts.length > 0,
   862→                        )
   863→                        .map((message) => (
   864→                          <div className="space-y-3" key={message.id}>
   865→                            <Message from={message.role}>
   866→                              <MessageContent>
   867→                                <MessagePartRenderer
   868→                                  debugToolUi={false}
   869→                                  onAddImageToCanvas={(url) => {
   870→                                    executeCommand({
   871→                                      type: "add",
   872→                                      url,
   873→                                      mediaType: "image",
   874→                                    });
   875→                                  }}
   876→                                  parts={message.parts}
   877→                                />
   878→                              </MessageContent>
   879→                            </Message>
   880→                          </div>
   881→                        ))
   882→                    )}
   883→
   884→                    {/* Inline Loader - appears as assistant message when status is 'submitted' */}
   885→                    {status === "submitted" && (
   886→                      <div className="space-y-3">
   887→                        <Message from="assistant">
   888→                          <MessageContent className="rounded-[8px] bg-neutral-700sss p-2 shadow-sm backdrop-blur-sm">
   889→                            <div className="flex items-center space-x-2">
   890→                              <Spinner size={20} />
   891→                              <span className="text-gray-300 text-sm">
   892→                                Thinking...
   893→                              </span>
   894→                            </div>
   895→                          </MessageContent>
   896→                        </Message>
   897→                      </div>
   898→                    )}
   899→                  </ConversationContent>
   900→
   901→                  <ConversationScrollButton />
   902→                </Conversation>
   903→              </div>
   904→
   905→              {/* Sticky input */}
   906→              <div className="sticky bottom-0 z-40 w-full">
   907→                <InputBar
   908→                  className="w-full"
   909→                  disabled={isLoadingChats || !activeChatId}
   910→                  isAutoMode={isAutoMode}
   911→                  onAutoModeChange={setIsAutoMode}
   912→                  onImageModelChange={setSelectedImageModel}
   913→                  onVideoModelChange={setSelectedVideoModel}
   914→                  selectedImageModel={selectedImageModel}
   915→                  selectedVideoModel={selectedVideoModel}
   916→                  sendMessage={(message: Parameters<typeof sendMessage>[0]) =>
   917→                    sendMessage(message, {
   918→                      body: { globalSystemInstructions },
   919→                    })
   920→                  }
   921→                  status={status}
   922→                  stop={stop}
   923→                />
   924→              </div>
   925→            </>
   926→          )}
   927→
   928→          <SystemInstructionsDialog
   929→            globalSystemInstructions={globalSystemInstructions}
   930→            isSystemDialogOpen={isSystemDialogOpen}
   931→            onSubmit={(values) => {
   932→              saveGlobalSystemInstructions(
   933→                values.globalSystemInstructions,
   934→                userId,
   935→              );
   936→              setGlobalSystemInstructions(values.globalSystemInstructions);
   937→            }}
   938→            setIsSystemDialogOpen={setIsSystemDialogOpen}
   939→          />
   940→        </>
   941→      )}
   942→      {currenttab === "assets" && (
   943→        <AssetsSidebar
   944→          isOpen={currenttab === "assets"}
   945→          messages={messages}
   946→          onClose={() => setCurrenttab("chat")}
   947→        />
   948→      )}
   949→      {currenttab === "history" && (
   950→        <ChatHistorySidebar
   951→          activeChatId={activeChatId}
   952→          chats={allChats}
   953→          isOpen={currenttab === "history"}
   954→          onClose={() => setCurrenttab("chat")}
   955→          onDeleteChat={handleDeleteChat}
   956→          onRenameChat={handleRenameChat}
   957→          onSelectChat={(chatId) => {
   958→            handleSelectChat(chatId);
   959→            setCurrenttab("chat");
   960→          }}
   961→        />
   962→      )}
   963→    </div>
