"use client";

import {
  Context,
  ContextContent,
  ContextContentBody,
  ContextContentHeader,
  ContextInputUsage,
  ContextOutputUsage,
  ContextTrigger,
} from "@/components/ai-elements/context";
import { Icons } from "@/components/shared/helper/Icons";
import { Button } from "@/components/ui/button";

interface TokenUsage {
  totalTokens: number;
  inputTokens: number;
  outputTokens: number;
}

interface TokenUsageDisplayProps {
  usage: TokenUsage | null;
  modelId?: string;
  maxTokens?: number;
}

/**
 * TokenUsageDisplay - Displays token usage information using the AI Elements Context component.
 *
 * Shows a hover card with detailed token usage breakdown including:
 * - Input tokens (prompt)
 * - Output tokens (completion)
 * - Total tokens used
 * - Context window utilization
 * - Estimated cost (when modelId is provided)
 */
export function TokenUsageDisplay({
  usage,
  modelId = "anthropic/claude-haiku-4-5",
  maxTokens = 200_000,
}: TokenUsageDisplayProps) {
  // Format token count for display (e.g., 1500 -> "1.5K")
  const formatTokens = (tokens: number): string => {
    if (tokens === 0) return "0";
    if (tokens < 1000) return tokens.toString();
    return `${(tokens / 1000).toFixed(1)}K`;
  };

  // Don't render if no usage data available
  if (!usage) {
    return (
      <Button
        className="flex-center gap-1.5 rounded-full px-3 py-1.5 text-gray-400 hover:bg-background-400"
        disabled
        size="none"
        type="button"
        variant="none"
      >
        <Icons.credits className="size-4" />
        <span className="text-sm">Tokens</span>
      </Button>
    );
  }

  return (
    <Context
      maxTokens={maxTokens}
      modelId={modelId}
      usage={{
        totalTokens: usage.totalTokens,
        promptTokens: usage.inputTokens,
        completionTokens: usage.outputTokens,
        inputTokens: usage.inputTokens,
        outputTokens: usage.outputTokens,
      }}
      usedTokens={usage.totalTokens}
    >
      <ContextTrigger asChild>
        <Button
          className="flex-center gap-1.5 rounded-full px-3 py-1.5 text-white transition-colors hover:bg-background-400"
          size="none"
          type="button"
          variant="none"
        >
          <Icons.credits className="size-4" />
          <span className="text-sm">
            {formatTokens(usage.totalTokens)} tokens
          </span>
        </Button>
      </ContextTrigger>
      <ContextContent>
        <ContextContentHeader />
        <ContextContentBody>
          <ContextInputUsage />
          <ContextOutputUsage />
        </ContextContentBody>
      </ContextContent>
    </Context>
  );
}
